// PaymentProcessor.kt
package com.example.paymentapp

import android.app.Activity
import android.util.Log
import com.android.billingclient.api.*

class PaymentProcessor(private val activity: Activity) : PurchasesUpdatedListener {

    private lateinit var billingClient: BillingClient

    init {
        setupBillingClient()
    }

    private fun setupBillingClient() {
        billingClient = BillingClient.newBuilder(activity)
            .setListener(this)
            .enablePendingPurchases()
            .build()

        billingClient.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    Log.i("PaymentProcessor", "Billing Setup Finished")
                }
            }

            override fun onBillingServiceDisconnected() {
                Log.w("PaymentProcessor", "Billing Service Disconnected")
            }
        })
    }

    fun queryAvailableProducts() {
        val skuList = listOf("premium_upgrade", "coins_100")
        val params = SkuDetailsParams.newBuilder()
        params.setSkusList(skuList).setType(BillingClient.SkuType.INAPP)

        billingClient.querySkuDetailsAsync(params.build(), SkuDetailsResponseListener { billingResult, skuDetailsList ->
            if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                skuDetailsList?.forEach { skuDetails ->
                    Log.i("PaymentProcessor", "Product ID: ${skuDetails.sku}, Price: ${skuDetails.price}")
                }
            }
        })
    }

    fun launchPurchaseFlow(productId: String) {
        val flowParams = BillingFlowParams.newBuilder()
            .setSkuDetails(SkuDetails.newBuilder().setSku(productId).setType(BillingClient.SkuType.INAPP).build())
            .build()
        billingClient.launchBillingFlow(activity, flowParams)
    }

    override fun onPurchasesUpdated(billingResult: BillingResult, purchases: MutableList<Purchase>?) {
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && purchases != null) {
            for (purchase in purchases) {
                handlePurchase(purchase)
            }
        }
    }

    private fun handlePurchase(purchase: Purchase) {
        Log.i("PaymentProcessor", "Purchase successful: ${purchase.sku}")
        // Securely store purchase data, send to backend server for verification
    }
}

